const config=require("./config");async function testOpenSeaWalletActivity(){console.log("🧪 Testing OpenSea API v2 Wallet Activity...");const testWallet="0x834711f749fe36dc4a5ae135267b88d0aaad8f3d";try{config.opensea.apiKey;console.log(`🔍 Testing OpenSea Stream API for wallet: ${testWallet}`);const ws=new(require("ws"))("wss://stream.openseabeta.com/socket/websocket");return ws.on("open",(function(){console.log("✅ Connected to OpenSea Stream API");const subscribeMessage={event:"phx_join",topic:`account:${testWallet}`,payload:{},ref:0};ws.send(JSON.stringify(subscribeMessage)),console.log("📡 Subscribed to wallet events"),setTimeout((()=>{ws.close(),console.log("🔌 Disconnected from Stream API")}),1e4)})),ws.on("message",(function(data){console.log("📨 Received:",data.toString())})),void ws.on("error",(function(err){console.error("❌ WebSocket error:",err.message)}))}catch(error){console.error("❌ Error:",error.message)}}testOpenSeaWalletActivity();